        # Return list of empty tensors with appropriate shapes
        if isinstance(indices_or_sections, int):
            n = indices_or_sections
        else:
            n = (
                len(indices_or_sections) + 1
                if isinstance(indices_or_sections, (list, tuple))
                else 1
            )
        output_tensors = []
